import { Disposable, DocumentLink, DocumentLinkProvider, ExtensionContext, languages, Range, TextDocument, Uri } from 'vscode';

export function activate(context: ExtensionContext): Disposable {
	const provider = new JavaDocumentLinkProvider();
	const disposable = languages.registerDocumentLinkProvider({ scheme: 'file', language: 'java' }, provider);
	context.subscriptions.push(disposable);
	return disposable;
}

export function deactivate(): void {
	// Nothing to do
}

class JavaDocumentLinkProvider implements DocumentLinkProvider {
	provideDocumentLinks(document: TextDocument, token: any): DocumentLink[] {
		const links: DocumentLink[] = [];
		const text = document.getText();
		const regex = /import\s+([a-zA-Z0-9_.]+)\.([a-zA-Z0-9_]+);/g;
		let match;
		while ((match = regex.exec(text)) !== null) {
			const packageName = match[1];
			const className = match[2];
			const startPos = document.positionAt(match.index);
			const endPos = document.positionAt(match.index + match[0].length);
			const range = new Range(startPos, endPos);
			const target = Uri.parse(`java://${packageName}.${className}`);
			links.push(new DocumentLink(range, target));
		}
		return links;
	}
}
